protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Blog>(b =>
    {
        // EF9 renamed the default discriminator from "Discriminator" to "$type".
        // Preserve the old name so existing documents are still recognized.
        b.HasDiscriminator<string>("Discriminator");

        // EF9 stopped embedding the discriminator in the JSON id property.
        // Preserve the old "Blog|1" format so existing documents remain accessible.
        b.HasRootDiscriminatorInJsonId(true);

        // EF9 Cosmos provider now throws on HasIndex (indexing is managed via
        // the Cosmos DB indexing policy, not EF). Removed the previous HasIndex call.
    });
}

